<div class="flex items-center justify-between mb-6"><div><h3 class="text-lg font-semibold text-gray-800 dark:text-white">Notificações</h3></div><form action="/admin/notificacoes/todas-lidas" method="POST"><?= \Core\View::csrf() ?><?= \Core\View::method('PUT') ?><button type="submit" class="px-4 py-2 text-sm text-purple-600 hover:text-purple-700 font-medium">Marcar todas como lidas</button></form></div><div class="space-y-2"><?php foreach ($notifications as $n): ?><div class="bg-white dark:bg-gray-800 rounded-xl p-4 border border-gray-100 dark:border-gray-700 flex items-start gap-4 <?= !$n['is_read'] ? 'border-l-4 border-l-purple-500' : '' ?>"><div class="w-10 h-10 bg-purple-100 dark:bg-purple-900/30 rounded-full flex items-center justify-center flex-shrink-0"><i data-lucide="bell" class="w-4 h-4 text-purple-600 dark:text-purple-400"></i></div><div class="flex-1"><p class="text-sm font-medium text-gray-800 dark:text-white"><?= htmlspecialchars($n['title']) ?></p><?php if ($n['message']): ?><p class="text-xs text-gray-500 mt-0.5"><?= htmlspecialchars($n['message']) ?></p><?php endif; ?><p class="text-xs text-gray-400 mt-1"><?= date('d/m/Y H:i', strtotime($n['created_at'])) ?></p></div></div><?php endforeach; ?><?php if (empty($notifications)): ?><div class="bg-white dark:bg-gray-800 rounded-xl p-12 border border-gray-100 dark:border-gray-700 text-center"><i data-lucide="bell-off" class="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-3"></i><p class="text-gray-500">Nenhuma notificação.</p></div><?php endif; ?></div>